<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Ubuntu Desktop</title>
<style>
  * { box-sizing: border-box; margin: 0; padding: 0; }
  html, body { height: 100%; overflow: hidden; }
  body {
    font-family: "Ubuntu", "Segoe UI", "Helvetica Neue", sans-serif;
    color: #f2f2f2;
    user-select: none;
  }

  /* ---------- Desktop ---------- */
  #desktop {
    position: fixed;
    inset: 0;
    background:
      radial-gradient(circle at 25% 20%, #6d2b4f 0%, transparent 55%),
      radial-gradient(circle at 80% 75%, #5a1f3d 0%, transparent 50%),
      linear-gradient(135deg, #2c001e 0%, #772953 55%, #300a24 100%);
    overflow: hidden;
  }

  #desktop-label {
    position: absolute;
    top: 50%; left: 50%;
    transform: translate(-50%, -50%);
    text-align: center;
    color: rgba(255,255,255,0.18);
    pointer-events: none;
  }
  #desktop-label h1 { font-size: 64px; font-weight: 300; letter-spacing: 4px; }
  #desktop-label p { font-size: 16px; margin-top: 8px; letter-spacing: 2px; }

  /* ---------- Taskbar / Dock ---------- */
  #taskbar {
    position: absolute;
    top: 0; left: 0;
    width: 56px; height: 100%;
    background: rgba(20, 8, 18, 0.85);
    backdrop-filter: blur(8px);
    border-right: 1px solid rgba(255,255,255,0.08);
    display: flex;
    flex-direction: column;
    align-items: center;
    padding: 10px 0;
    gap: 10px;
    z-index: 5000;
  }
  .launcher {
    width: 44px; height: 44px;
    border-radius: 10px;
    border: none;
    cursor: pointer;
    display: flex;
    align-items: center;
    justify-content: center;
    font-size: 22px;
    color: #fff;
    background: rgba(255,255,255,0.06);
    transition: background 0.15s, transform 0.1s;
    position: relative;
  }
  .launcher:hover { background: rgba(233,84,32,0.85); transform: translateY(-1px); }
  .launcher:active { transform: translateY(0); }
  .launcher .tip {
    position: absolute;
    left: 52px;
    white-space: nowrap;
    background: #111;
    color: #fff;
    padding: 4px 8px;
    border-radius: 4px;
    font-size: 12px;
    opacity: 0;
    pointer-events: none;
    transition: opacity 0.15s;
  }
  .launcher:hover .tip { opacity: 1; }

  /* Top bar */
  #topbar {
    position: absolute;
    top: 0; left: 56px; right: 0;
    height: 28px;
    background: rgba(20, 8, 18, 0.9);
    display: flex;
    align-items: center;
    justify-content: center;
    font-size: 13px;
    letter-spacing: 1px;
    z-index: 4000;
    border-bottom: 1px solid rgba(255,255,255,0.06);
  }
  #topbar .right { position: absolute; right: 14px; font-size: 12px; opacity: 0.8; }

  /* ---------- Windows ---------- */
  .window {
    position: absolute;
    top: 90px; left: 140px;
    width: 640px; height: 440px;
    min-width: 360px; min-height: 240px;
    background: #2b2b2b;
    border-radius: 8px;
    box-shadow: 0 18px 50px rgba(0,0,0,0.55);
    border: 1px solid rgba(255,255,255,0.08);
    display: none;
    flex-direction: column;
    overflow: hidden;
    z-index: 10;
  }
  .window.show { display: flex; }

  .titlebar {
    height: 36px;
    background: linear-gradient(#3a3a3a, #303030);
    display: flex;
    align-items: center;
    padding: 0 10px;
    cursor: move;
    flex-shrink: 0;
    border-bottom: 1px solid rgba(0,0,0,0.3);
  }
  .titlebar .title { font-size: 13px; flex: 1; opacity: 0.9; }
  .win-btns { display: flex; gap: 8px; }
  .win-btns button {
    width: 14px; height: 14px;
    border-radius: 50%;
    border: none;
    cursor: pointer;
  }
  .win-min { background: #ffbd2e; }
  .win-max { background: #28c940; }
  .win-close { background: #ff5f56; }

  /* ---------- Files app ---------- */
  .files-toolbar {
    display: flex;
    align-items: center;
    gap: 8px;
    padding: 8px 10px;
    background: #333;
    border-bottom: 1px solid rgba(0,0,0,0.3);
    flex-shrink: 0;
  }
  .files-toolbar button {
    background: #4a4a4a;
    color: #fff;
    border: 1px solid rgba(255,255,255,0.1);
    border-radius: 5px;
    padding: 5px 10px;
    cursor: pointer;
    font-size: 13px;
  }
  .files-toolbar button:hover { background: #565656; }
  #files-path {
    flex: 1;
    background: #1f1f1f;
    padding: 5px 10px;
    border-radius: 5px;
    font-family: "Ubuntu Mono", monospace;
    font-size: 13px;
    color: #e95420;
    overflow: hidden;
    text-overflow: ellipsis;
    white-space: nowrap;
  }
  .files-list {
    flex: 1;
    overflow-y: auto;
    padding: 10px;
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(96px, 1fr));
    gap: 6px;
    align-content: start;
  }
  .fs-item {
    display: flex;
    flex-direction: column;
    align-items: center;
    gap: 4px;
    padding: 10px 6px;
    border-radius: 6px;
    cursor: pointer;
    text-align: center;
    transition: background 0.1s;
  }
  .fs-item:hover { background: rgba(255,255,255,0.07); }
  .fs-item.selected { background: rgba(233,84,32,0.35); }
  .fs-item .icon { font-size: 30px; line-height: 1; }
  .fs-item .name {
    font-size: 12px;
    word-break: break-word;
    max-width: 90px;
  }

  /* ---------- Notepad app ---------- */
  #notepad-window { width: 560px; height: 420px; left: 260px; top: 130px; }
  .notepad-body { display: flex; flex-direction: column; flex: 1; overflow: hidden; }
  #tabs {
    display: flex;
    align-items: center;
    background: #262626;
    border-bottom: 1px solid rgba(0,0,0,0.4);
    overflow-x: auto;
    flex-shrink: 0;
  }
  .tab {
    display: flex;
    align-items: center;
    gap: 6px;
    padding: 8px 12px;
    font-size: 13px;
    cursor: pointer;
    border-right: 1px solid rgba(0,0,0,0.4);
    white-space: nowrap;
    background: #2f2f2f;
    color: #ccc;
    max-width: 160px;
  }
  .tab.active { background: #1e1e1e; color: #fff; border-bottom: 2px solid #e95420; }
  .tab .tab-name { overflow: hidden; text-overflow: ellipsis; }
  .tab .tab-close {
    font-size: 14px;
    line-height: 1;
    opacity: 0.6;
    border-radius: 3px;
    padding: 0 3px;
  }
  .tab .tab-close:hover { opacity: 1; background: rgba(255,255,255,0.15); }
  #new-tab {
    flex-shrink: 0;
    background: transparent;
    color: #fff;
    border: none;
    font-size: 20px;
    cursor: pointer;
    padding: 4px 12px;
  }
  #new-tab:hover { background: rgba(255,255,255,0.1); }
  #editor {
    flex: 1;
    background: #1e1e1e;
    color: #f0f0f0;
    border: none;
    outline: none;
    resize: none;
    padding: 14px;
    font-family: "Ubuntu Mono", "Consolas", monospace;
    font-size: 14px;
    line-height: 1.5;
    width: 100%;
  }
</style>
</head>
<body>
<div id="desktop">
  <div id="desktop-label">
    <h1>Ubuntu</h1>
    <p>Desktop Environment</p>
  </div>

  <div id="topbar">
    <span>Activities</span>
    <span class="right" id="clock"></span>
  </div>

  <!-- Dock / Taskbar -->
  <div id="taskbar">
    <button id="open-files" class="launcher" title="Files">
      📁<span class="tip">Files</span>
    </button>
    <button id="open-notepad" class="launcher" title="Notepad">
      📝<span class="tip">Notepad</span>
    </button>
  </div>

  <!-- Files Window -->
  <div id="files-window" class="window">
    <div class="titlebar" data-window="files-window">
      <span class="title">Files</span>
      <div class="win-btns">
        <button class="win-min" title="Minimize"></button>
        <button class="win-max" title="Maximize"></button>
        <button class="win-close" title="Close"></button>
      </div>
    </div>
    <div class="files-toolbar">
      <button id="files-up" title="Parent folder">↑ Up</button>
      <div id="files-path">/</div>
    </div>
    <div class="files-list" id="files-list"></div>
  </div>

  <!-- Notepad Window -->
  <div id="notepad-window" class="window">
    <div class="titlebar" data-window="notepad-window">
      <span class="title">Notepad</span>
      <div class="win-btns">
        <button class="win-min" title="Minimize"></button>
        <button class="win-max" title="Maximize"></button>
        <button class="win-close" title="Close"></button>
      </div>
    </div>
    <div class="notepad-body">
      <div style="display:flex; align-items:stretch;">
        <div id="tabs" style="flex:1;"></div>
        <button id="new-tab" title="New tab">+</button>
      </div>
      <textarea id="editor" spellcheck="false" placeholder="Start typing..."></textarea>
    </div>
  </div>
</div>

<script>
(function () {
  "use strict";

  /* =========================================================
     Clock
  ========================================================= */
  function tick() {
    var d = new Date();
    var el = document.getElementById("clock");
    if (el) el.textContent = d.toLocaleDateString() + "  " +
      d.toLocaleTimeString([], { hour: "2-digit", minute: "2-digit" });
  }
  tick();
  setInterval(tick, 1000 * 30);

  /* =========================================================
     Window management (open/close/drag/focus)
  ========================================================= */
  var zTop = 100;
  function focusWindow(win) { win.style.zIndex = ++zTop; }

  function openWindow(win) {
    win.classList.add("show");
    focusWindow(win);
  }
  function closeWindow(win) {
    win.classList.remove("show");
  }

  document.getElementById("open-files").addEventListener("click", function () {
    openWindow(document.getElementById("files-window"));
  });
  document.getElementById("open-notepad").addEventListener("click", function () {
    openWindow(document.getElementById("notepad-window"));
  });

  // Close buttons
  document.querySelectorAll(".win-close").forEach(function (btn) {
    btn.addEventListener("click", function () {
      closeWindow(btn.closest(".window"));
    });
  });

  // Focus on mousedown anywhere in window
  document.querySelectorAll(".window").forEach(function (win) {
    win.addEventListener("mousedown", function () { focusWindow(win); });
  });

  // Dragging via titlebar
  document.querySelectorAll(".titlebar").forEach(function (bar) {
    var win = bar.closest(".window");
    var dragging = false, ox = 0, oy = 0;
    bar.addEventListener("mousedown", function (e) {
      if (e.target.closest(".win-btns")) return;
      dragging = true;
      var rect = win.getBoundingClientRect();
      ox = e.clientX - rect.left;
      oy = e.clientY - rect.top;
      focusWindow(win);
      e.preventDefault();
    });
    document.addEventListener("mousemove", function (e) {
      if (!dragging) return;
      var nx = e.clientX - ox;
      var ny = e.clientY - oy;
      nx = Math.max(56, Math.min(nx, window.innerWidth - 80));
      ny = Math.max(28, Math.min(ny, window.innerHeight - 60));
      win.style.left = nx + "px";
      win.style.top = ny + "px";
    });
    document.addEventListener("mouseup", function () { dragging = false; });
  });

  /* =========================================================
     Files app — fake Linux filesystem
  ========================================================= */
  var FS = {
    "bin": { type: "dir", children: {
      "bash": { type: "file" }, "ls": { type: "file" },
      "cat": { type: "file" }, "grep": { type: "file" }
    }},
    "etc": { type: "dir", children: {
      "hostname": { type: "file" }, "passwd": { type: "file" },
      "hosts": { type: "file" }, "fstab": { type: "file" }
    }},
    "home": { type: "dir", children: {
      "user": { type: "dir", children: {
        "Documents": { type: "dir", children: {
          "resume.pdf": { type: "file" },
          "notes.txt": { type: "file" },
          "Projects": { type: "dir", children: {
            "app.html": { type: "file" }, "README.md": { type: "file" }
          }}
        }},
        "Downloads": { type: "dir", children: {
          "ubuntu.iso": { type: "file" }, "photo.png": { type: "file" }
        }},
        "Pictures": { type: "dir", children: {
          "wallpaper.jpg": { type: "file" }, "screenshot.png": { type: "file" }
        }},
        ".bashrc": { type: "file" },
        "todo.txt": { type: "file" }
      }}
    }},
    "usr": { type: "dir", children: {
      "bin": { type: "dir", children: { "python3": { type: "file" }, "node": { type: "file" } }},
      "lib": { type: "dir", children: {} },
      "share": { type: "dir", children: { "icons": { type: "dir", children: {} } } }
    }},
    "var": { type: "dir", children: {
      "log": { type: "dir", children: { "syslog": { type: "file" }, "auth.log": { type: "file" } }},
      "tmp": { type: "dir", children: {} },
      "www": { type: "dir", children: { "index.html": { type: "file" } } }
    }}
  };

  var currentPath = []; // array of segment names

  function nodeAtPath(segments) {
    var children = FS;
    var node = { type: "dir", children: FS };
    for (var i = 0; i < segments.length; i++) {
      if (!children || !children[segments[i]]) return null;
      node = children[segments[i]];
      children = node.children;
    }
    return node;
  }

  function pathString() {
    return "/" + currentPath.join("/");
  }

  function renderFiles() {
    var pathEl = document.getElementById("files-path");
    pathEl.textContent = pathString();

    var node = nodeAtPath(currentPath);
    var list = document.getElementById("files-list");
    list.innerHTML = "";
    if (!node || node.type !== "dir") return;

    var children = node.children || {};
    var names = Object.keys(children).sort(function (a, b) {
      var da = children[a].type === "dir", db = children[b].type === "dir";
      if (da !== db) return da ? -1 : 1;
      return a.localeCompare(b);
    });

    names.forEach(function (name) {
      var entry = children[name];
      var isDir = entry.type === "dir";
      var item = document.createElement("div");
      item.className = "fs-item";
      item.dataset.name = name;
      item.dataset.type = entry.type;

      var icon = document.createElement("div");
      icon.className = "icon";
      icon.textContent = isDir ? "📁" : "📄";

      var label = document.createElement("div");
      label.className = "name";
      label.textContent = name;

      item.appendChild(icon);
      item.appendChild(label);

      item.addEventListener("click", function (e) {
        list.querySelectorAll(".fs-item.selected").forEach(function (s) {
          s.classList.remove("selected");
        });
        item.classList.add("selected");
      });

      item.addEventListener("dblclick", function () {
        if (isDir) {
          currentPath.push(name);
          renderFiles();
        }
      });

      list.appendChild(item);
    });
  }

  document.getElementById("files-up").addEventListener("click", function () {
    if (currentPath.length > 0) {
      currentPath.pop();
      renderFiles();
    }
  });

  renderFiles();

  /* =========================================================
     Notepad app — tabbed, persistent via localStorage
  ========================================================= */
  var STORAGE_KEY = "ubuntu_notepad_tabs_v1";
  var tabsData = [];   // [{ id, name, content }]
  var activeId = null;
  var seq = 1;

  function loadState() {
    try {
      var raw = localStorage.getItem(STORAGE_KEY);
      if (raw) {
        var parsed = JSON.parse(raw);
        if (parsed && Array.isArray(parsed.tabs)) {
          tabsData = parsed.tabs;
          activeId = parsed.activeId;
          // compute seq beyond existing ids
          tabsData.forEach(function (t) {
            var n = parseInt(String(t.id).replace(/\D/g, ""), 10);
            if (!isNaN(n) && n >= seq) seq = n + 1;
          });
        }
      }
    } catch (e) { /* ignore corrupt storage */ }

    if (!tabsData.length) {
      var t = newTabObject();
      tabsData.push(t);
      activeId = t.id;
    }
    if (!activeId || !tabsData.some(function (t) { return t.id === activeId; })) {
      activeId = tabsData[0].id;
    }
  }

  function saveState() {
    try {
      localStorage.setItem(STORAGE_KEY, JSON.stringify({
        tabs: tabsData, activeId: activeId
      }));
    } catch (e) { /* storage may be unavailable */ }
  }

  function newTabObject() {
    var id = "tab" + (seq++);
    return { id: id, name: "Untitled " + id.replace("tab", ""), content: "" };
  }

  function getActive() {
    return tabsData.filter(function (t) { return t.id === activeId; })[0];
  }

  function renderTabs() {
    var tabsEl = document.getElementById("tabs");
    tabsEl.innerHTML = "";
    tabsData.forEach(function (t) {
      var tab = document.createElement("div");
      tab.className = "tab" + (t.id === activeId ? " active" : "");
      tab.dataset.id = t.id;

      var nm = document.createElement("span");
      nm.className = "tab-name";
      nm.textContent = t.name || "Untitled";

      var close = document.createElement("span");
      close.className = "tab-close";
      close.textContent = "×";
      close.title = "Close tab";
      close.addEventListener("click", function (e) {
        e.stopPropagation();
        closeTab(t.id);
      });

      tab.appendChild(nm);
      tab.appendChild(close);

      tab.addEventListener("click", function () {
        setActive(t.id);
      });

      tabsEl.appendChild(tab);
    });
  }

  function renderEditor() {
    var editor = document.getElementById("editor");
    var active = getActive();
    editor.value = active ? active.content : "";
  }

  function setActive(id) {
    activeId = id;
    renderTabs();
    renderEditor();
    saveState();
  }

  function addTab() {
    var t = newTabObject();
    tabsData.push(t);
    activeId = t.id;
    renderTabs();
    renderEditor();
    saveState();
    document.getElementById("editor").focus();
  }

  function closeTab(id) {
    var idx = tabsData.findIndex(function (t) { return t.id === id; });
    if (idx === -1) return;
    tabsData.splice(idx, 1);
    if (!tabsData.length) {
      var t = newTabObject();
      tabsData.push(t);
      activeId = t.id;
    } else if (activeId === id) {
      activeId = tabsData[Math.max(0, idx - 1)].id;
    }
    renderTabs();
    renderEditor();
    saveState();
  }

  document.getElementById("new-tab").addEventListener("click", addTab);

  document.getElementById("editor").addEventListener("input", function () {
    var active = getActive();
    if (!active) return;
    active.content = this.value;
    // Derive tab name from first non-empty line
    var firstLine = this.value.split("\n")[0].trim();
    active.name = firstLine ? firstLine.slice(0, 20) : "Untitled";
    // update the visible tab label without full re-render (keep caret)
    var tabEl = document.querySelector('.tab[data-id="' + active.id + '"] .tab-name');
    if (tabEl) tabEl.textContent = active.name;
    saveState();
  });

  loadState();
  renderTabs();
  renderEditor();

})();
</script>
</body>
</html>
